				    // Ændrer datatyper: Kommunenummer til heltal og Kommunenavn til tekst
				    #"Ændr Kolonne Typer" = Table.TransformColumnTypes(#"Omdøb Kolonner", {{"Kommunenummer", Int64.Type}, {"Kommunenavn", type text}}),

				    // ============================
				    // ➕ SEKTION 3: Tilpasninger
				    // ============================
