				    // Fjerner rækker med tomme værdier i Kommunenummer
				    #"Fjern Tomme Værdier" = Table.SelectRows(#"Fjern Dubletter", each ([Kommunenummer] <> null)),

				    // Tilføjer en ekstra kolonne "Kommune Key" som kopi af Kommunenummer (bruges til slicer-søgning)
