				    // ============================
				    // 🧹 SEKTION 4: Oprydning og sortering
				    // ============================
				    #"🧹 Oprydning" = #"Ændr Kommunenummer Til Tekst",

				    // Sorterer alfabetisk på Kommunenavn
				    #"Sorteret Alfabetisk" = Table.Sort(#"🧹 Oprydning", {{"Kommunenavn", Order.Ascending}}),

				    // Tilføjer løbenummer fra 1 som Index
				    #"Added Index" = Table.AddIndexColumn(#"Sorteret Alfabetisk", "Index", 1, 1, Int64.Type),

				    // Tilføjer en ekstra række øverst med "Vælg Kommune"
				    #"Tilføj Vælg Kommune Række" = Table.InsertRows(
				        #"Added Index",
				        0,
				        {
				            [Kommune Key = 0, Kommunenummer = "0", Kommunenavn = "Vælg Kommune", Index = 0]
				        }
				    )
				in
				    #"Tilføj Vælg Kommune Række"

