let
				    Source = #"Samlede Nøgletal",
				    KDK2025_Sheet = Source{[Item="KDK2025",Kind="Sheet"]}[Data],
				    #"Promoted Headers" = Table.PromoteHeaders(KDK2025_Sheet, [PromoteAllScalars=true]),
				    #"== Transformations" = #"Promoted Headers",
				    #"Fjernet Kommunenavn" = Table.RemoveColumns(#"== Transformations",{"Kommunenavn"}),
				    #"Renamed Columns" = Table.RenameColumns(#"Fjernet Kommunenavn",{{"Kommunnummer", "Kommunenummer"}}),
				    #"Changed Type" = Table.TransformColumnTypes(#"Renamed Columns",{{"ID", Int64.Type}, {"Periode", Int64.Type}, {"Kommunenummer", Int64.Type}, {"Udtræksdato", type text}, {"Ikke publiceret", Int64.Type}}),
				    // Der er flere af de studerende, som har brugt "-" istedet for at efterlade cellen blank når en kommune ikke har haft nogen værdi. Det håndtere vi i den følgende logik.
				    #"= Håndter ""-""" = #"Changed Type",
				    #"Skift datatype til tekst" = Table.TransformColumnTypes(#"= Håndter ""-""",{{"Resultat", type text}, {"Tæller", type text}, {"Nævner", type text}, {"Sidste års nøgletal", type text}}),
				    #"Udskift ""-"" med null" = Table.ReplaceValue(#"Skift datatype til tekst","-",null,Replacer.ReplaceValue,{"Resultat", "Tæller", "Nævner", "Sidste års nøgletal"}),
				    #"Skift datatype til fixed decimal" = Table.TransformColumnTypes(#"Udskift ""-"" med null",{{"Resultat", Currency.Type}, {"Tæller", Currency.Type}, {"Nævner", Currency.Type}, {"Sidste års nøgletal", Currency.Type}}),
				    // For at kunne lave en rapport der kan springe mellem alle spørgsmål uanset enhed, så er det nødvendigt, at vi får ensartet værdierne. Derfor skal alt det, hvor det står i procent. ganges med 100
				    #"= Korriger for procent" = #"Skift datatype til fixed decimal",
				    #"Merged Queries" = Table.NestedJoin(#"= Korriger for procent", {"ID"}, Enhed, {"IDnummer"}, "Enhed", JoinKind.LeftOuter),
				    #"Expanded Enhed" = Table.ExpandTableColumn(#"Merged Queries", "Enhed", {"Enhed", "Rangeringsorden"}, {"Enhed", "Rangeringsorden"}),

				    // Se formel linje for betingelser, men her sørger vi for, at pct. og lignende bliver behandlet efter hensigten.
				    #"Tilføj Resultat - Korrigeret" = Table.AddColumn(#"Expanded Enhed", "Resultat - Korrigeret",
				    each if [ID] = 10076 then [Resultat] //I det her tilfælde er der allerede korrigeret for procent i kilden.
				    else if [Tæller] = 0 and [Nævner] = 1 then null
				    else if [Enhed] = "pct." then [Resultat] * 100
				    else if [Enhed] = "dagsværk pct." then [Resultat] * 100
				    else if [Enhed] = "procentpoint" then [Resultat] * 100

				    else [Resultat],
				    type number),
				    #"Tilføj Sidste års resultat - Korrigeret" = Table.AddColumn(#"Tilføj Resultat - Korrigeret", "Sidste års resultat - Korrigeret",
				    each if
				            //I de her tilfælde er der allerede korrigeret for procent i kilden.
				            List.Contains({10076, 10011, 10085},[ID])
				            then [Sidste års nøgletal]
				    else if [Sidste års nøgletal] = 0 then null
				    else if [Enhed] = "pct." then [Sidste års nøgletal] * 100
				    else if [Enhed] = "dagsværk pct." then [Sidste års nøgletal] * 100
				    else if [Enhed] = "procentpoint" then [Sidste års nøgletal] * 100

				    else [Sidste års nøgletal],
				    type number),
				    #"= Tilføj Ranks" = #"Tilføj Sidste års resultat - Korrigeret",

				// Fortsæt fra dit sidste step
				Base = #"= Tilføj Ranks",

				// (Anbefalet) Sikr korrekte datatyper
				BaseTyped = Table.TransformColumnTypes(
				    Base,
				    {{"ID", type text}, {"Kommunenummer", Int64.Type}, {"Resultat - Korrigeret", type number}}
				),

				// Gruppér pr. spørgsmål (ID)
				#"Grupperet pr. ID" =
				    Table.Group(
				        BaseTyped,
				        {"ID"},
				        {{"All", each _, type table}}
				    ),

				/*
				    Beregn competition-ranks pr. ID:
				    - Null sidst: vi tilføjer "NullFlag" (0=ikke-null, 1=null) og sorterer primært på den.
				    - Competition rank: rang = første forekomsts position i den sorterede værdiliste + 1.
				    - Rank (ASC): lavest er bedst
				    - Omvendt Rank (DESC): højest er bedst
				*/
				#"Tilføj ranks pr. gruppe" =
				    Table.AddColumn(
				        #"Grupperet pr. ID",
				        "Ranks",
				        each
				            let
				                t0 = [All],

				                // Robust adgang til kolonnen (mellemrum/bindestreg i navnet)
				                // NullFlag = 1 for null, ellers 0 (null skal altid sidst)
				                tWithFlag =
				                    Table.AddColumn(
				                        t0,
				                        "NullFlag",
				                        each if Value.Is(Record.Field(_, "Resultat - Korrigeret"), type null) then 1 else 0,
				                        Int64.Type
				                    ),

				                // --- ASC: Lavest er bedst -> Rank ---
				                tAsc =
				                    Table.Sort(
				                        tWithFlag,
				                        {{"NullFlag", Order.Ascending},
				                         {"Resultat - Korrigeret", Order.Ascending},
				                         {"Kommunenummer", Order.Ascending}}
				                    ),
				                valuesAsc = Table.Column(tAsc, "Resultat - Korrigeret"),
				                ranksAsc = List.Transform(valuesAsc, (v) => List.PositionOf(valuesAsc, v) + 1),
				                tAscRanked =
				                    Table.FromColumns(
				                        Table.ToColumns(tAsc) & {ranksAsc},
				                        Table.ColumnNames(tAsc) & {"Rank"}
				                    ),

				                // --- DESC: Højest er bedst -> Omvendt Rank ---
				                tDesc =
				                    Table.Sort(
				                        tWithFlag,
				                        {{"NullFlag", Order.Ascending},
				                         {"Resultat - Korrigeret", Order.Descending},
				                         {"Kommunenummer", Order.Ascending}}
				                    ),
				                valuesDesc = Table.Column(tDesc, "Resultat - Korrigeret"),
				                ranksDesc = List.Transform(valuesDesc, (v) => List.PositionOf(valuesDesc, v) + 1),
				                tDescRanked =
				                    Table.FromColumns(
				                        Table.ToColumns(tDesc) & {ranksDesc},
				                        Table.ColumnNames(tDesc) & {"Omvendt Rank"}
				                    ),

				                // Join ASC og DESC ranks på Kommunenummer (ID er ens inden for gruppen)
				                tJoined =
				                    Table.NestedJoin(
				                        tAscRanked, {"Kommunenummer"},
				                        Table.SelectColumns(tDescRanked, {"Kommunenummer", "Omvendt Rank"}), {"Kommunenummer"},
				                        "Tmp", JoinKind.LeftOuter
				                    ),
				                tMerged = Table.ExpandTableColumn(tJoined, "Tmp", {"Omvendt Rank"}, {"Omvendt Rank"}),

				                // Fjern hjælpekolonnen NullFlag før vi sender ranktabellen videre
				                tOut = Table.RemoveColumns(tMerged, {"NullFlag"})
				            in
				                // Ranktabellen indeholder også ID, men vi udvider den ikke ud igen med ID
				                Table.SelectColumns(tOut, {"ID", "Kommunenummer", "Resultat - Korrigeret", "Rank", "Omvendt Rank"})
				    ),

				/* Fladgør ranktabellen til én tabel (UDEN at udvide ID for at undgå konflikt) */
				#"Udvid Ranks" =
				    Table.ExpandTableColumn(
				        #"Tilføj ranks pr. gruppe",
				        "Ranks",
				        {"Kommunenummer", "Resultat - Korrigeret", "Rank", "Omvendt Rank"},
				        {"Kommunenummer", "Resultat - Korrigeret", "Rank", "Omvendt Rank"}
				    ),

				/* Merge ranks tilbage på den fulde tabel (bevarer alle eksisterende kolonner) */
				#"Join tilbage" =
				    Table.NestedJoin(
				        BaseTyped, {"ID", "Kommunenummer"},
				        #"Udvid Ranks", {"ID", "Kommunenummer"},
				        "RankTbl",
				        JoinKind.LeftOuter
				    ),
				#"Udvid Rank-kolonner" =
				    Table.ExpandTableColumn(
				        #"Join tilbage",
				        "RankTbl",
				        {"Rank", "Omvendt Rank"},
				        {"Rank", "Omvendt Rank"}
				    ),

				/* (Valgfrit) Sæt heltalstype på rankkolonner */
				#"Sæt typer" =
				    Table.TransformColumnTypes(
				        #"Udvid Rank-kolonner",
				        {{"Rank", Int64.Type}, {"Omvendt Rank", Int64.Type}}
				    ),

				/*-------------------------------------------------------------------------*/

				// Fortsæt fra dit sidste step
				#"LY - Base" =
				    #"Sæt typer",

				// (Anbefalet) Sikr korrekte datatyper
				#"LY - BaseTyped" =
				    Table.TransformColumnTypes(
				        #"LY - Base",
				        {{"ID", type text}, {"Kommunenummer", Int64.Type}, {"Sidste års resultat - Korrigeret", type number}}
				    ),

				// Gruppér pr. spørgsmål (ID)
				#"LY - Grupperet pr. ID" =
				    Table.Group(
				        #"LY - BaseTyped",
				        {"ID"},
				        {{"All", each _, type table}}
				    ),

				/*
				    Beregn competition-ranks pr. ID på "Sidste års resultat - Korrigeret":
				    - Null sidst: tilføj "NullFlag" (0=ikke-null, 1=null) og sortér primært på den.
				    - Competition rank: rang = første forekomsts position i den sorterede værdiliste + 1.
				    - Rank - Forrige år (ASC): lavest er bedst
				    - Omvendt Rank - Forrige år (DESC): højest er bedst
				*/
				#"LY - Tilføj ranks pr. gruppe" =
				    Table.AddColumn(
				        #"LY - Grupperet pr. ID",
				        "Ranks",
				        each
				            let
				                t0 = [All],

				                // NullFlag = 1 for null, ellers 0 (null skal altid sidst)
				                tWithFlag =
				                    Table.AddColumn(
				                        t0,
				                        "NullFlag",
				                        each if Value.Is(Record.Field(_, "Sidste års resultat - Korrigeret"), type null) then 1 else 0,
				                        Int64.Type
				                    ),

				                // --- ASC: Lavest er bedst -> Rank - Forrige år ---
				                tAsc =
				                    Table.Sort(
				                        tWithFlag,
				                        {{"NullFlag", Order.Ascending},
				                         {"Sidste års resultat - Korrigeret", Order.Ascending},
				                         {"Kommunenummer", Order.Ascending}}
				                    ),
				                valuesAsc = Table.Column(tAsc, "Sidste års resultat - Korrigeret"),
				                // Competition: første position i den sorterede liste + 1
				                ranksAsc = List.Transform(valuesAsc, (v) => List.PositionOf(valuesAsc, v) + 1),
				                tAscRanked =
				                    Table.FromColumns(
				                        Table.ToColumns(tAsc) & {ranksAsc},
				                        Table.ColumnNames(tAsc) & {"Rank - Forrige år"}
				                    ),

				                // --- DESC: Højest er bedst -> Omvendt Rank - Forrige år ---
				                tDesc =
				                    Table.Sort(
				                        tWithFlag,
				                        {{"NullFlag", Order.Ascending},
				                         {"Sidste års resultat - Korrigeret", Order.Descending},
				                         {"Kommunenummer", Order.Ascending}}
				                    ),
				                valuesDesc = Table.Column(tDesc, "Sidste års resultat - Korrigeret"),
				                ranksDesc = List.Transform(valuesDesc, (v) => List.PositionOf(valuesDesc, v) + 1),
				                tDescRanked =
				                    Table.FromColumns(
				                        Table.ToColumns(tDesc) & {ranksDesc},
				                        Table.ColumnNames(tDesc) & {"Omvendt Rank - Forrige år"}
				                    ),

				                // Join ASC- og DESC-ranks på Kommunenummer (ID er ens inden for gruppen)
				                tJoined =
				                    Table.NestedJoin(
				                        tAscRanked, {"Kommunenummer"},
				                        Table.SelectColumns(tDescRanked, {"Kommunenummer", "Omvendt Rank - Forrige år"}), {"Kommunenummer"},
				                        "Tmp", JoinKind.LeftOuter
				                    ),
