// tager version fra disconnected budget tabel, år fra forecast (år) slicer


VAR _Year = SELECTEDVALUE('Forecast sammenlign'[År])
VAR _Ver  = SELECTEDVALUE('Forecast sammenlign'[Version navn])
RETURN
IF(
OR(ISBLANK(_Year), ISBLANK(_Ver)),
BLANK(),
CALCULATE(
[Forecast],
// fjern filter fra år og version
REMOVEFILTERS( 'Forecast'[År], 'Forecast'[Version navn] ),
// tilføj værdier fra disconnected tabel
TREATAS(
ROW("År", _Year, "Version navn", _Ver),
'Forecast'[År], 'Forecast'[Version navn]
)
)
)

